236 void VPPredicator::convertPhisToBlends(VPBasicBlock *VPBB) {
237   SmallVector<VPPhi *> Phis;
238   for (VPRecipeBase &R : VPBB->phis())
239     Phis.push_back(cast<VPPhi>(&R));
240   for (VPPhi *PhiR : Phis) {
241     // The non-header Phi is converted into a Blend recipe below,
242     // so we don't have to worry about the insertion order and we can just use
243     // the builder. At this point we generate the predication tree. There may
244     // be duplications since this is a simple recursive scan, but future
245     // optimizations will clean it up.
246 
247     if (all_equal(PhiR->incoming_values())) {
248       PhiR->replaceAllUsesWith(PhiR->getIncomingValue(0));
249       PhiR->eraseFromParent();
250       continue;
251     }
252 
253     SmallVector<VPValue *, 2> OperandsWithMask;
254     for (const auto &[InVPV, InVPBB] : PhiR->incoming_values_and_blocks()) {
255       OperandsWithMask.push_back(InVPV);
256       OperandsWithMask.push_back(getEdgeMask(InVPBB, VPBB));
257     }
258     PHINode *IRPhi = cast_or_null<PHINode>(PhiR->getUnderlyingValue());
259     auto *Blend =
260         new VPBlendRecipe(IRPhi, OperandsWithMask, PhiR->getDebugLoc());
261     Builder.insert(Blend);
262     PhiR->replaceAllUsesWith(Blend);
263     PhiR->eraseFromParent();
264   }
265 }
