268 VPlanTransforms::introduceMasksAndLinearize(VPlan &Plan, bool FoldTail) {
269   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
270   // Scan the body of the loop in a topological order to visit each basic block
271   // after having visited its predecessor basic blocks.
272   VPBasicBlock *Header = LoopRegion->getEntryBasicBlock();
273   ReversePostOrderTraversal<VPBlockShallowTraversalWrapper<VPBlockBase *>> RPOT(
274       Header);
275   VPPredicator Predicator;
276   for (VPBlockBase *VPB : RPOT) {
277     // Non-outer regions with VPBBs only are supported at the moment.
278     auto *VPBB = cast<VPBasicBlock>(VPB);
279     // Introduce the mask for VPBB, which may introduce needed edge masks, and
280     // convert all phi recipes of VPBB to blend recipes unless VPBB is the
281     // header.
282     if (VPBB == Header) {
283       Predicator.createHeaderMask(Header, FoldTail);
284       continue;
285     }
286 
287     Predicator.createBlockInMask(VPBB);
288     Predicator.convertPhisToBlends(VPBB);
289   }
290 
291   // Linearize the blocks of the loop into one serial chain.
292   VPBlockBase *PrevVPBB = nullptr;
293   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(RPOT)) {
294     auto Successors = to_vector(VPBB->getSuccessors());
295     if (Successors.size() > 1)
296       VPBB->getTerminator()->eraseFromParent();
297 
298     // Flatten the CFG in the loop. To do so, first disconnect VPBB from its
299     // successors. Then connect VPBB to the previously visited VPBB.
300     for (auto *Succ : Successors)
301       VPBlockUtils::disconnectBlocks(VPBB, Succ);
302     if (PrevVPBB)
303       VPBlockUtils::connectBlocks(PrevVPBB, VPBB);
304 
305     PrevVPBB = VPBB;
306   }
307 
308   // If we folded the tail and introduced a header mask, any extract of the
309   // last element must be updated to extract from the last active lane of the
310   // header mask instead (i.e., the lane corresponding to the last active
311   // iteration).
312   if (FoldTail) {
313     assert(Plan.getExitBlocks().size() == 1 &&
314            "only a single-exit block is supported currently");
315     assert(Plan.getExitBlocks().front()->getSinglePredecessor() ==
316                Plan.getMiddleBlock() &&
317            "the exit block must have middle block as single predecessor");
318 
319     VPBuilder B(Plan.getMiddleBlock()->getTerminator());
320     for (VPRecipeBase &R : *Plan.getMiddleBlock()) {
321       VPValue *Op;
322       if (!match(&R, m_ExtractLastLane(m_ExtractLastPart(m_VPValue(Op)))))
323         continue;
324 
325       // Compute the index of the last active lane.
326       VPValue *HeaderMask = Predicator.getBlockInMask(Header);
327       VPValue *LastActiveLane =
328           B.createNaryOp(VPInstruction::LastActiveLane, HeaderMask);
329       auto *Ext =
330           B.createNaryOp(VPInstruction::ExtractLane, {LastActiveLane, Op});
331       R.getVPSingleValue()->replaceAllUsesWith(Ext);
332     }
333   }
334   return Predicator.getBlockMaskCache();
335 }
